mapper.select:
SELECT COUNT(1)
FROM ${schema}.user
WHERE user_id = #{userId}

	AND user_oid != #{userOid}

SELECT user_oid
FROM   ${schema}.user
WHERE user_id = #{request.userId}
  AND  user_nm_korn = #{request.name}
  AND  brdt        = #{request.brdt}
  AND  mpno_pfx    = #{request.mpnoPfx}
  AND  ${schema}.fn_decrypt_aes(mpno_mid, #{secretKey}) = CAST(#{request.mpnoMid} AS CHAR) COLLATE utf8mb4_unicode_ci
  AND  mpno_sfx    = #{request.mpnoSfx}
  AND  use_yn = 'Y'
LIMIT 1
